class Solution:
    def longestPalindrome(self, s: str, t: str) -> int:
        st = s + t
        n = len(s)
        ans = 0
        for i in range(len(st)):
            for j in range(min(i+1, len(st)-i)):
                if st[i-j] == st[i+j]:
                    if i-j < n and i+j >= n:
                        ans = max(ans, 2*(j)+1)
                    else:
                        ans = max(ans, 2*(j))
                else:
                    break
        return ans
